mapper.select:
        SELECT buff_id, user_id, buff_type, name, stat_type, effect_pct, expires_at, created_at
        FROM buffs

		WHERE user_id=#{userId}
		AND name=#{name}

		AND (

		expires_at IS NULL

		OR expires_at > NOW()

		)

		LIMIT 1

mapper.delete:
DELETE FROM buffs
WHERE user_id = #{userId}
  AND name    = #{name}

DELETE FROM buffs
WHERE buff_id = (
    SELECT buff_id FROM (
        SELECT buff_id FROM buffs
        WHERE user_id  = #{userId}
          AND buff_type = 'DEBUFF'
        ORDER BY created_at ASC
        LIMIT 1
    ) AS oldest
)

mapper.update:
UPDATE buffs
SET progress = progress + 1
WHERE buff_id = #{buffId}

mapper.select:
SELECT buff_id, user_id, buff_type, name, stat_type, effect_pct, expires_at, created_at,
       linked_quest_id AS linkedQuestId, progress
FROM buffs
WHERE user_id         = #{userId}
  AND linked_quest_id = #{questId}
LIMIT 1
